    /// Required level for `job`, or null if the job can't use the spell (or no data).
    public static byte? For(ushort spellId, byte job)
    {
        if (!ByJob.TryGetValue(spellId, out var pairs)) return null;
        foreach (var (j, lvl) in pairs) if (j == job) return lvl;
        return null;
    }

    public static bool HasData(ushort spellId) => ByJob.ContainsKey(spellId);
}
